import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import FooterRojo from "../components/FooterRojo";
import "../styles/EditarSalaCompleto.css";

function EditarSalaCompleto() {
  const [salas, setSalas] = useState([]);
  const [tab, setTab] = useState("info"); // 🔥 tabs

  const [salaSeleccionada, setSalaSeleccionada] = useState(null);

  const [form, setForm] = useState({
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const [estado, setEstado] = useState("");

  const obtenerSalas = async () => {
    try {
      const res = await fetch("http://localhost:3001/api/salas", {
        credentials: "include"
      });
      const data = await res.json();
      setSalas(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    obtenerSalas();
  }, []);

  const seleccionarSala = (s) => {
    setSalaSeleccionada(s);

    setForm({
      nombre: s.nombre,
      ubicacion: s.ubicacion,
      capacidad: s.capacidad
    });

    setEstado(s.estado);
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // 🔹 EDITAR INFO
  const editarInfo = async () => {
    if (!salaSeleccionada) return alert("Selecciona una sala");

    await fetch(`http://localhost:3001/api/salas/${salaSeleccionada.id}/datos`, {
      method: "PUT",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        nombre: form.nombre,
        ubicacion: form.ubicacion,
        capacidad: Number(form.capacidad)
      })
    });

    alert("Información actualizada ✅");
    obtenerSalas();
  };

  // 🔹 EDITAR ESTADO
  const editarEstado = async () => {
    if (!salaSeleccionada) return alert("Selecciona una sala");

    await fetch(`http://localhost:3001/api/salas/${salaSeleccionada.id}`, {
      method: "PUT",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        estado: estado.toLowerCase()
      })
    });

    alert("Estado actualizado ✅");
    obtenerSalas();
  };

  return (
    <div className="container">
      <NavbarGestionSalas />

      <div className="content">

        {/* IZQUIERDA */}
        <div className="formSection">

          <h2>
            {salaSeleccionada
              ? `Sala: ${salaSeleccionada.nombre}`
              : "Selecciona una sala"}
          </h2>

          {/* 🔥 TABS */}
          <div className="tabs">
            <button
              className={tab === "info" ? "active" : ""}
              onClick={() => setTab("info")}
            >
              Editar Info
            </button>

            <button
              className={tab === "estado" ? "active" : ""}
              onClick={() => setTab("estado")}
            >
              Editar Estado
            </button>
          </div>

          {/* 🔹 TAB INFO */}
          {tab === "info" && (
            <>
              <div className="formGroup">
                <label>Nombre:</label>
                <input name="nombre" value={form.nombre} onChange={handleChange} />
              </div>

              <div className="formGroup">
                <label>Ubicación:</label>
                <input name="ubicacion" value={form.ubicacion} onChange={handleChange} />
              </div>

              <div className="formGroup">
                <label>Capacidad:</label>
                <input type="number" name="capacidad" value={form.capacidad} onChange={handleChange} />
              </div>

              <button className="btn azul" onClick={editarInfo}>
                Guardar Cambios
              </button>
            </>
          )}

          {/* 🔹 TAB ESTADO */}
          {tab === "estado" && (
            <>
              <div className="formGroup">
                <label>Estado:</label>
                <select value={estado} onChange={(e) => setEstado(e.target.value)}>
                  <option value="">Seleccione</option>
                  <option value="disponible">Disponible</option>
                  <option value="ocupado">Ocupado</option>
                  <option value="mantenimiento">Mantenimiento</option>
                </select>
              </div>

              <button className="btn rojo" onClick={editarEstado}>
                Actualizar Estado
              </button>
            </>
          )}

        </div>

        {/* DERECHA */}
        <div className="listSection">
          {salas.map((s) => (
            <div
              key={s.id}
              className={`card ${salaSeleccionada?.id === s.id ? "active" : ""}`}
              onClick={() => seleccionarSala(s)}
            >
              <h3>{s.nombre}</h3>
              <p>{s.ubicacion}</p>

              <div className="info">
                <span>👥 {s.capacidad}</span>
                <span className={`estado ${s.estado}`}>
                  {s.estado}
                </span>
              </div>
            </div>
          ))}
        </div>

      </div>

      <FooterRojo />
    </div>
  );
}

export default EditarSalaCompleto;
